external_knowledge:
- 'Active users' refers to those whose status is marked as 'Active';
- 'Players drafted recently' refers to players drafted after the year 2010;
- 'Games in the last few years' refers to games played after January 1, 2020.

sql:
SELECT players.player_id, players.first_name, players.last_name
FROM players
JOIN player_injuries ON players.player_id = player_injuries.player_id;
